import { useEffect, useState } from 'react';

export function useDocumentVisibility(): DocumentVisibilityState {
  const [documentVisibility, setDocumentVisibility] = useState<DocumentVisibilityState>('visible');

  useEffect(() => {
    setDocumentVisibility(document.visibilityState);
    const listener = () => setDocumentVisibility(document.visibilityState);
    document.addEventListener('visibilitychange', listener);
    return () => document.removeEventListener('visibilitychange', listener);
  }, []);

  return documentVisibility;
}

export function getComparator(mimeType: string): Comparator {
  if (mimeType === 'image/png')
    return compareImages.bind(null, 'image/png');
  if (mimeType === 'image/jpeg')
    return compareImages.bind(null, 'image/jpeg');
  if (mimeType === 'text/plain')
    return compareText;
  return compareBuffersOrStrings;
}

export function Bind(...decorators: any[]): MethodDecorator {
  return <T>(
    target: object,
    key: string | symbol,
    descriptor: TypedPropertyDescriptor<T>,
  ) => {
    decorators.forEach((fn, index) => fn(target, key, index));
    return descriptor;
  };
}

export function Redirect(url = '', statusCode?: number): MethodDecorator {
  return (
    target: object,
    key: string | symbol,
    descriptor: TypedPropertyDescriptor<any>,
  ) => {
    Reflect.defineMetadata(
      REDIRECT_METADATA,
      { statusCode, url },
      descriptor.value,
    );
    return descriptor;
  };
}

export function Header(
  name: string,
  value: string | (() => string),
): MethodDecorator {
  return (
    target: object,
    key: string | symbol,
    descriptor: TypedPropertyDescriptor<any>,
  ) => {
    extendArrayMetadata(HEADERS_METADATA, [{ name, value }], descriptor.value);
    return descriptor;
  };
}

export function useShallow<S, U>(selector: (state: S) => U): (state: S) => U {
  const prev = React.useRef<U>(undefined)
  return (state) => {
    const next = selector(state)
    return shallow(prev.current, next)
      ? (prev.current as U)
      : (prev.current = next)
  }
}

get<S extends Schema>(schema: S): $replace<Meta, S> | undefined {
  // return this._map.get(schema) as any;

  // inherit metadata
  const p = schema._zod.parent as Schema;
  if (p) {
    const pm: any = { ...(this.get(p) ?? {}) };
    delete pm.id; // do not inherit id
    const f = { ...pm, ...this._map.get(schema) } as any;
    return Object.keys(f).length ? f : undefined;
  }
  return this._map.get(schema) as any;
}

export function cached<T>(getter: () => T): { value: T } {
  const set = false;
  return {
    get value() {
      if (!set) {
        const value = getter();
        Object.defineProperty(this, "value", { value });
        return value;
      }
      throw new Error("cached value already set");
    },
  };
}

export function mergeDefs(...defs: Record<string, any>[]): any {
  const mergedDescriptors: Record<string, PropertyDescriptor> = {};

  for (const def of defs) {
    const descriptors = Object.getOwnPropertyDescriptors(def);
    Object.assign(mergedDescriptors, descriptors);
  }

  return Object.defineProperties({}, mergedDescriptors);
}

export function aborted(x: schemas.ParsePayload, startIndex = 0): boolean {
  if (x.aborted === true) return true;
  for (let i = startIndex; i < x.issues.length; i++) {
    if (x.issues[i]?.continue !== true) {
      return true;
    }
  }
  return false;
}

export function explicitlyAborted(x: schemas.ParsePayload, startIndex = 0): boolean {
  if (x.aborted === true) return true;
  for (let i = startIndex; i < x.issues.length; i++) {
    if (x.issues[i]?.continue === false) {
      return true;
    }
  }
  return false;
}

export function createGuid(): string {
  return crypto.randomBytes(16).toString('hex');
}

export function calculateSha1(buffer: Buffer | string): string {
  const hash = crypto.createHash('sha1');
  hash.update(buffer);
  return hash.digest('hex');
}

export function isRegExp(obj: any): obj is RegExp {
  return obj instanceof RegExp || Object.prototype.toString.call(obj) === '[object RegExp]';
}

export function isRegexString(value: string): boolean {
  try {
    new RegExp(value);
    return true;
  } catch {
    return false;
  }
}

export function guessClientName(): string {
  if (process.env.CLAUDECODE)
    return 'Claude Code';
  if (process.env.COPILOT_CLI)
    return 'GitHub Copilot';
  return 'playwright-cli';
}

export function isCodingAgent(): boolean {
  return !!process.env.CLAUDECODE || !!process.env.COPILOT_CLI;
}

export function compareBuffersOrStrings(actualBuffer: Buffer | string, expectedBuffer: Buffer): ComparatorResult {
  if (typeof actualBuffer === 'string')
    return compareText(actualBuffer, expectedBuffer);
  if (!actualBuffer || !(actualBuffer instanceof Buffer))
    return { errorMessage: 'Actual result should be a Buffer or a string.' };
  if (Buffer.compare(actualBuffer, expectedBuffer))
    return { errorMessage: 'Buffers differ' };
  return null;
}

export class TargetClosedError extends PlaywrightError {
  constructor(cause?: string) {
    super(cause || 'Target page, context or browser has been closed');
  }
}

export function isTargetClosedError(error: Error) {
  return error instanceof TargetClosedError;
}

export function serializeError(e: any): SerializedError {
  if (isError(e))
    return { error: { message: e.message, stack: e.stack, name: e.name } };
  return { value: serializeValue(e, value => ({ fallThrough: value })) };
}

matches(url: URL): boolean {
  if (this._raw.secure && (url.protocol !== 'https:' && !isLocalHostname(url.hostname)))
    return false;
  if (!domainMatches(url.hostname, this._raw.domain))
    return false;
  if (!pathMatches(url.pathname, this._raw.path))
    return false;
  return true;
}

export function isSystemDirectory(dir: string): boolean {
  const resolved = path.resolve(dir);
  if (process.platform === 'win32') {
    const systemRoot = path.resolve(process.env.SystemRoot || 'C:\\Windows');
    return isPathInside(systemRoot.toLowerCase(), resolved.toLowerCase());
  }
  return resolved === '/';
}

increment(field: "major" | "minor" | "patch"): Version {
    switch (field) {
        case "major":
            return new Version(this.major + 1, 0, 0);
        case "minor":
            return new Version(this.major, this.minor + 1, 0);
        case "patch":
            return new Version(this.major, this.minor, this.patch + 1);
        default:
            return Debug.assertNever(field);
    }
}

with(fields: { major?: number; minor?: number; patch?: number; prerelease?: string | readonly string[]; build?: string | readonly string[]; }): Version {
    const {
        major = this.major,
        minor = this.minor,
        patch = this.patch,
        prerelease = this.prerelease,
        build = this.build,
    } = fields;
    return new Version(major, minor, patch, prerelease, build);
}

function createTextChunk(text: string): TextChunk {
    const textLowerCase = text.toLowerCase();
    return {
        text,
        textLowerCase,
        isLowerCase: text === textLowerCase,
        characterSpans: breakIntoCharacterSpans(text),
    };
}

function addSource(fileName: string) {
    enter();
    const source = getRelativePathToDirectoryOrUrl(sourcesDirectoryPath, fileName, host.getCurrentDirectory(), host.getCanonicalFileName, /*isAbsolutePathAnUrl*/ true);

    let sourceIndex = sourceToSourceIndexMap.get(source);
    if (sourceIndex === undefined) {
        sourceIndex = sources.length;
        sources.push(source);
        rawSources.push(fileName);
        sourceToSourceIndexMap.set(source, sourceIndex);
    }
    exit();
    return sourceIndex;
}

export function Catch(
  ...exceptions: Array<Type<any> | Abstract<any>>
): ClassDecorator {
  return (target: object) => {
    Reflect.defineMetadata(CATCH_WATERMARK, true, target);
    Reflect.defineMetadata(FILTER_CATCH_EXCEPTIONS, exceptions, target);
  };
}

const getTrackedConnectionState = (
  name: string | undefined,
): Record<string, any> => {
  const api = trackedConnections.get(name)
  if (!api) return {}
  return Object.fromEntries(
    Object.entries(api.stores).map(([key, api]) => [key, api.getState()]),
  )
}

const parseJsonThen = <T>(stringified: string, fn: (parsed: T) => void) => {
  let parsed: T | undefined
  try {
    parsed = JSON.parse(stringified)
  } catch (e) {
    console.error(
      '[zustand devtools middleware] Could not parse the received json',
      e,
    )
  }
  if (parsed !== undefined) fn(parsed as T)
}

export function isDate(value: unknown): value is Date {
  return (
    value instanceof Date ||
    // date created in other JS context (for example, worker)
    Object.prototype.toString.call(value) === '[object Date]'
  )
}

export function isValidDate(date: Date) {
  return date.toString() !== 'Invalid Date'
}

// Same logic as https://github.com/sindresorhus/is-interactive/blob/dc8037ae1a61d828cfb42761c345404055b1e036/index.js
// But defaults to check `stdin` for our prompts
// It checks that the stream is TTY, not a dumb terminal

type Options = {
  stream?: NodeJS.ReadStream
}
export const isInteractive = ({ stream = process.stdin }: Options = {}): boolean => {
  return Boolean(stream && stream.isTTY && process.env.TERM !== 'dumb')
}

export async function getEngineVersion(enginePath?: string, binaryName?: BinaryType): Promise<string> {
  enginePath = await resolveBinary(binaryName ?? BinaryType.SchemaEngineBinary, enginePath)

  const { stdout } = await execa(enginePath, ['--version'])
  return stdout
}

export function importPipeline() {
  let importGate: Promise<void> = Promise.resolve();

  return async (importFn: () => Promise<ModuleExports>) => {
    await importGate;

    const moduleExportsPromise = importFn();
    importGate = importGate.then(async () => {
      await moduleExportsPromise;
    });
    return moduleExportsPromise;
  };
}
